import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.oauth2.client.OAuth2RestTemplate;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.client.userinfo.DefaultOAuth2UserService;
import org.springframework.security.oauth2.client.userinfo.OAuth2UserRequest;
import org.springframework.security.oauth2.client.userinfo.OAuth2UserService;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.SecurityFilterChain;

@SpringBootApplication
public class OidcClientApplication {

    public static void main(String[] args) {
        SpringApplication.run(OidcClientApplication.class, args);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .authorizeHttpRequests((authorize) -> authorize.anyRequest().authenticated())
                .oauth2Login()
                .userInfoEndpoint()
                .userService(oidcUserService());
        return http.build();
    }

    @Bean
    public OAuth2UserService<OAuth2UserRequest, OidcUser> oidcUserService() {
        DefaultOAuth2UserService delegate = new DefaultOAuth2UserService();
        return new OidcUserService(delegate);
    }

    private static class OidcUserService extends DefaultOAuth2UserService {

        private final OAuth2RestTemplate restTemplate;

        public OidcUserService(OAuth2RestTemplate restTemplate) {
            this.restTemplate = restTemplate;
        }

        @Override
        public OidcUser loadUser(OAuth2UserRequest userRequest) {
            OidcUser oidcUser = (OidcUser) super.loadUser(userRequest);
            DefaultOidcUser.Builder builder = DefaultOidcUser.builder();
            builder.token(oidcUser.getIdToken().getTokenValue());
            builder.claims(oidcUser.getIdToken().getClaims());
            return builder.build();
        }
    }
}